// Row 1 goes left → right, Row 2 goes right → left
const ROW_1 = TECH_STACK.slice(0, Math.ceil(TECH_STACK.length / 2));
const ROW_2 = TECH_STACK.slice(Math.ceil(TECH_STACK.length / 2));

// ─── Marquee Row Component ─────────────────────────────────────────────────────
function MarqueeRow({ items, direction = 1, speed = 40 }) {
  const outerRef = useRef(null);
  const trackRef = useRef(null);
  const animRef = useRef(null);

  // Duplicate items for seamless loop (2 copies is enough)
  const doubled = [...items, ...items];

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;

    // Width of one full set
    const halfWidth = track.scrollWidth / 2;
    const dur = halfWidth / speed;

    // LTR: slide from 0 → -halfWidth, then snap back
    // RTL: slide from -halfWidth → 0, then snap forward
    const fromX = direction === 1 ? 0 : -halfWidth;
    const toX = direction === 1 ? -halfWidth : 0;

    gsap.set(track, { x: fromX });

    const tween = gsap.to(track, {
      x: toX,
      duration: dur,
      ease: 'none',
      repeat: -1,
    });

    animRef.current = tween;
    return () => tween.kill();
  }, [direction, speed]);

  const handleMouseEnter = () => {
    if (animRef.current) {
      gsap.to(animRef.current, { timeScale: 0.1, duration: 0.5, ease: 'power2.out' });
    }
  };

  const handleMouseLeave = () => {
    if (animRef.current) {
      gsap.to(animRef.current, { timeScale: 1, duration: 0.8, ease: 'power2.inOut' });
    }
  };

  return (
    <div
      ref={outerRef}
      className="marquee-row-outer"
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <div className="marquee-track" ref={trackRef}>
        {doubled.map((tech, i) => (
          <TechIcon key={`${tech.name}-${i}`} tech={tech} />
        ))}
      </div>
    </div>
  );
}

// ─── Tech Icon Card ─────────────────────────────────────────────────────────
function TechIcon({ tech }) {
  const [hovered, setHovered] = useState(false);

  return (
    <motion.div
      className="tech-icon-card"
      onHoverStart={() => setHovered(true)}
      onHoverEnd={() => setHovered(false)}
      whileHover={{ scale: 1.12, y: -2 }}
      transition={{ type: 'spring', stiffness: 400, damping: 25 }}
    >
      <motion.div
        className="tech-icon-inner"
        animate={{
          opacity: hovered ? 1 : 0.35,
          filter: hovered
            ? 'brightness(1.8) drop-shadow(0 0 12px rgba(255,255,255,0.25))'
            : 'brightness(0.6)',
        }}
        transition={{ duration: 0.2, ease: 'easeOut' }}
      >
        <div className="tech-icon-svg">{tech.icon}</div>
      </motion.div>

      {/* Tooltip */}
      <motion.div
        className="tech-tooltip"
        initial={{ opacity: 0, scale: 0.92 }}
        animate={hovered ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.92 }}
        transition={{ duration: 0.18, ease: 'easeOut' }}
      >
        {tech.name}
      </motion.div>
    </motion.div>
  );
}

